package cn.org.starpivot.api.fallback;import cn.org.starpivot.api.mall.ware.MallWareInternalClient;import org.springframework.cloud.openfeign.FallbackFactory;public class MallWareInternalClientFallbackFactory implements FallbackFactory<MallWareInternalClient> {    private static final String ACTION = "商城仓储服务";    @Override    public MallWareInternalClient create(Throwable cause) {        return request -> FeignFallbackSupport.unavailable(cause, ACTION);    }}